def merge_breaks(blocks):
    # Merge later break first to preserve earlier raw index.
    for li,start in [(92,'Wind led'),(7,'Lord Rickard,')]:
        left,right=blocks[li],blocks[li+1]
        assert right['text'].startswith(start)
        left['text']+=' '+right['text']; left['end_page']=right['end_page']; del blocks[li+1]
    for i,b in enumerate(blocks,1): b['order']=i; b['id']=f"CH24-P{int(b['page']):03d}-{i:03d}"
    return blocks

